import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"各大航空公司对比","description":"国内外主要航空公司的服务和航线对比","frontmatter":{"title":"各大航空公司对比","description":"国内外主要航空公司的服务和航线对比"},"headers":[],"relativePath":"knowledge/flights/airlines.md","filePath":"knowledge/flights/airlines.md","lastUpdated":null}'),l={name:"knowledge/flights/airlines.md"};function o(n,a,s,d,h,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="各大航空公司对比" tabindex="-1">各大航空公司对比 <a class="header-anchor" href="#各大航空公司对比" aria-label="Permalink to &quot;各大航空公司对比&quot;">​</a></h1><h2 id="国内航空公司" tabindex="-1">国内航空公司 <a class="header-anchor" href="#国内航空公司" aria-label="Permalink to &quot;国内航空公司&quot;">​</a></h2><p>国航、南航、东航和海航覆盖国内主要国际航线。国航的欧洲航线网络最完善，南航在大洋洲航线上有优势。</p><h2 id="亚洲航空公司" tabindex="-1">亚洲航空公司 <a class="header-anchor" href="#亚洲航空公司" aria-label="Permalink to &quot;亚洲航空公司&quot;">​</a></h2><p>全日空、新加坡航空和国泰航空常年位列全球最佳航空公司前列。服务品质出色但价格相对较高。</p><h2 id="欧洲航空公司" tabindex="-1">欧洲航空公司 <a class="header-anchor" href="#欧洲航空公司" aria-label="Permalink to &quot;欧洲航空公司&quot;">​</a></h2><p>汉莎航空、法航和荷兰皇家航空是欧洲的主要航司。瑞安航空和易捷航空是欧洲最大的廉价航空公司。</p><h2 id="廉价航空对比" tabindex="-1">廉价航空对比 <a class="header-anchor" href="#廉价航空对比" aria-label="Permalink to &quot;廉价航空对比&quot;">​</a></h2><p>亚航、捷星和春秋航空是亚洲知名廉航。廉航通常不包含餐饮和行李，购买时需计算附加费用。</p>',9)])])}const f=e(l,[["render",o]]);export{_ as __pageData,f as default};
